using MiniCRUFT.World;

namespace MiniCRUFT.Rendering;

public sealed class RendererHost
{
    private readonly Dictionary<(ChunkCoordinate ChunkCoordinate, int SubchunkIndex), SubchunkMeshingOutput> _uploadedSubchunkMeshes = new();

    public int UploadedSubchunkMeshCount => _uploadedSubchunkMeshes.Count;

    public void Initialize()
    {
    }

    public int PickupBuiltSubchunkMeshingOutputs(WorldHost world)
    {
        ArgumentNullException.ThrowIfNull(world);

        var consumedCount = 0;
        while (world.TryDrainNextBuiltSubchunkMeshingOutput(out var output))
        {
            var consumedOutput = output!;
            _uploadedSubchunkMeshes[(consumedOutput.ChunkCoordinate, consumedOutput.SubchunkIndex)] = consumedOutput;
            consumedCount++;
        }

        return consumedCount;
    }

    public bool TryGetUploadedSubchunkMesh(ChunkCoordinate chunkCoordinate, int subchunkIndex, out SubchunkMeshingOutput? output)
    {
        return _uploadedSubchunkMeshes.TryGetValue((chunkCoordinate, subchunkIndex), out output);
    }

    public void RenderFrame()
    {
    }

    public void Shutdown()
    {
        _uploadedSubchunkMeshes.Clear();
    }
}
